from __future__ import annotations
from dataclasses import dataclass, field
from typing import TypeVar, Generic

T = TypeVar("T")

@dataclass
class ToolResult(Generic[T]):
    """Typed result envelope for agent tool calls."""
    ok: bool
    data: T | None = None
    error: str | None = None

    @classmethod
    def success(cls, data: T) -> ToolResult[T]:
        return cls(ok=True, data=data)

    @classmethod
    def failure(cls, error: str) -> ToolResult[T]:
        return cls(ok=False, error=error)

# Type checker knows result.data is list[str], not Any
search_result: ToolResult[list[str]] = ToolResult.success(["Paris", "Lyon"])
print(search_result.data)    # ['Paris', 'Lyon']
print(type(search_result.data))  # list

# And here data is dict[str, int]
count_result: ToolResult[dict[str, int]] = ToolResult.success({"tokens": 150})
# mypy knows count_result.data is dict[str, int]

from __future__ import annotations
from typing import Protocol, runtime_checkable

Message = dict[str, str]

@runtime_checkable
class SupportsChatCompletion(Protocol):
    """Any LLM client that can produce a chat completion."""

    def complete(
        self,
        messages: list[Message],
        *,
        max_tokens: int = 1024,
    ) -> str:
        ...

# Implementations — note: NO inheritance from SupportsChatCompletion
class OpenAIAdapter:
    def __init__(self, model: str = "gpt-4o") -> None:
        self.model = model

    def complete(self, messages: list[Message], *, max_tokens: int = 1024) -> str:
        import openai
        resp = openai.chat.completions.create(
            model=self.model, messages=messages, max_tokens=max_tokens
        )
        return resp.choices[0].message.content or ""

class LocalLlamaAdapter:
    def __init__(self, model_path: str) -> None:
        self.model_path = model_path

    def complete(self, messages: list[Message], *, max_tokens: int = 1024) -> str:
        # Local inference via llama.cpp or similar
        return f"[Local response to {messages[-1]['content']!r}]"

# Function accepts any SupportsChatCompletion — not a specific class
def run_agent(
    client: SupportsChatCompletion,
    user_message: str,
) -> str:
    messages: list[Message] = [{"role": "user", "content": user_message}]
    return client.complete(messages)

# Both work — type checker verifies structural conformance
openai_adapter = OpenAIAdapter()
local_adapter = LocalLlamaAdapter("/models/llama-3.2-3b.gguf")

# Runtime check (requires @runtime_checkable)
assert isinstance(local_adapter, SupportsChatCompletion)

from typing import Protocol, TypeVar

T_co = TypeVar("T_co", covariant=True)  # covariant: read-only container

class Readable(Protocol[T_co]):
    """Anything you can read items from."""
    def read(self) -> T_co: ...

# A file-like reader
class TokenBuffer:
    def __init__(self, tokens: list[str]) -> None:
        self._tokens = tokens
        self._pos = 0

    def read(self) -> str:
        token = self._tokens[self._pos]
        self._pos += 1
        return token

# Type checker verifies TokenBuffer satisfies Readable[str]
def consume(reader: Readable[str]) -> list[str]:
    results = []
    try:
        while True:
            results.append(reader.read())
    except IndexError:
        return results

buf = TokenBuffer(["hello", "world"])
print(consume(buf))  # ['hello', 'world']

from typing import Callable, TypeVar
from functools import wraps

# ParamSpec preserves the full parameter spec of the wrapped function
try:
    from typing import ParamSpec
except ImportError:
    from typing_extensions import ParamSpec

P = ParamSpec("P")
R = TypeVar("R")

def log_call(fn: Callable[P, R]) -> Callable[P, R]:
    """Decorator that logs calls; preserves the wrapped function's full type."""
    @wraps(fn)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        print(f"Calling {fn.__name__}")
        result = fn(*args, **kwargs)
        print(f"Done: {fn.__name__} -> {result!r}")
        return result
    return wrapper

@log_call
def search(query: str, top_k: int = 5) -> list[str]:
    return [f"result_{i}" for i in range(top_k)]

# Type checker knows search still has signature (query: str, top_k: int = 5) -> list[str]
results = search("test", top_k=3)  # autocomplete works correctly

from typing import Protocol, TypeVar, Callable, Generic
from collections import defaultdict

Event = TypeVar("Event")

class EventHandler(Protocol[Event]):
    def __call__(self, event: Event) -> None: ...

class EventBus(Generic[Event]):
    def __init__(self) -> None:
        self._handlers: list[Callable[[Event], None]] = []

    def subscribe(self, handler: EventHandler[Event]) -> None:
        self._handlers.append(handler)

    def emit(self, event: Event) -> None:
        for h in self._handlers:
            h(event)

from dataclasses import dataclass

@dataclass
class ToolCallEvent:
    tool_name: str
    args: dict

bus: EventBus[ToolCallEvent] = EventBus()

def log_tool_call(event: ToolCallEvent) -> None:
    print(f"Tool called: {event.tool_name}({event.args})")

bus.subscribe(log_tool_call)
bus.emit(ToolCallEvent("search", {"query": "Paris"}))
# Tool called: search({'query': 'Paris'})

from typing import Generic, TypeVar
from functools import lru_cache

K = TypeVar("K")
V = TypeVar("V")

class TypedCache(Generic[K, V]):
    """Simple in-memory cache with typed key and value."""

    def __init__(self, max_size: int = 128) -> None:
        self._store: dict[K, V] = {}
        self._max = max_size

    def get(self, key: K) -> V | None:
        return self._store.get(key)  # type: ignore[arg-type]

    def set(self, key: K, value: V) -> None:
        if len(self._store) >= self._max:
            oldest = next(iter(self._store))
            del self._store[oldest]
        self._store[key] = value

    def __len__(self) -> int:
        return len(self._store)

# Type checker knows embeddings are list[float]
embedding_cache: TypedCache[str, list[float]] = TypedCache(max_size=1000)
embedding_cache.set("hello world", [0.1, 0.2, 0.3])
vec: list[float] | None = embedding_cache.get("hello world")
print(vec)  # [0.1, 0.2, 0.3]

from typing import Protocol

class VectorStore(Protocol):
    def upsert(self, id: str, embedding: list[float], metadata: dict) -> None: ...
    def query(self, embedding: list[float], top_k: int) -> list[dict]: ...
    def delete(self, id: str) -> None: ...

# Two concrete backends — no common base class

class PineconeStore:
    def __init__(self, index_name: str) -> None:
        self._index_name = index_name

    def upsert(self, id: str, embedding: list[float], metadata: dict) -> None:
        print(f"[Pinecone] upsert {id}")

    def query(self, embedding: list[float], top_k: int) -> list[dict]:
        return [{"id": f"doc_{i}", "score": 0.9 - i * 0.1} for i in range(top_k)]

    def delete(self, id: str) -> None:
        print(f"[Pinecone] delete {id}")

class InMemoryStore:
    def __init__(self) -> None:
        self._data: dict[str, tuple[list[float], dict]] = {}

    def upsert(self, id: str, embedding: list[float], metadata: dict) -> None:
        self._data[id] = (embedding, metadata)

    def query(self, embedding: list[float], top_k: int) -> list[dict]:
        return [{"id": k, "score": 0.5} for k in list(self._data)[:top_k]]

    def delete(self, id: str) -> None:
        del self._data[id]

# Works with either store — type checker verifies both satisfy VectorStore
def index_document(store: VectorStore, doc_id: str, text: str) -> None:
    embedding = [0.1] * 1536   # placeholder
    store.upsert(doc_id, embedding, {"text": text})

pinecone = PineconeStore("prod-index")
mem_store = InMemoryStore()

index_document(pinecone, "doc1", "The Eiffel Tower is in Paris.")
index_document(mem_store, "doc1", "The Eiffel Tower is in Paris.")

from __future__ import annotations
from typing import TypeVar, Generic, Protocol, Callable
from dataclasses import dataclass

I = TypeVar("I")  # input type
O = TypeVar("O")  # output type

@dataclass
class StageResult(Generic[O]):
    value: O
    metadata: dict

class PipelineStage(Protocol[I, O]):
    def run(self, input: I) -> StageResult[O]: ...

class TextChunker:
    """Satisfies PipelineStage[str, list[str]]."""
    def __init__(self, chunk_size: int = 512) -> None:
        self.chunk_size = chunk_size

    def run(self, input: str) -> StageResult[list[str]]:
        chunks = [input[i:i+self.chunk_size] for i in range(0, len(input), self.chunk_size)]
        return StageResult(value=chunks, metadata={"n_chunks": len(chunks)})

class EmbeddingGenerator:
    """Satisfies PipelineStage[list[str], list[list[float]]]."""
    def run(self, input: list[str]) -> StageResult[list[list[float]]]:
        embeddings = [[0.1 * i] * 384 for i, _ in enumerate(input)]
        return StageResult(value=embeddings, metadata={"dim": 384})

# Type-safe pipeline execution
chunker = TextChunker(chunk_size=200)
embedder = EmbeddingGenerator()

doc = "Generics and Protocols enable type-safe, pluggable Python architectures. " * 10
chunks_result = chunker.run(doc)
print(f"Chunks: {chunks_result.metadata['n_chunks']}")

embed_result = embedder.run(chunks_result.value)
print(f"Embeddings: {len(embed_result.value)} x {len(embed_result.value[0])} dims")
